import { effects } from '../../effects/zceffects';

export function applyClippathToLivePlot(data, holder, renderer, chart) {
    if (renderer.phase == 'redraw') {
        var clipX = renderer.scales.x(chart.dataset.getX(data[0]));
        var properties = {
                name: 'rect',
                id: chart.id,
                x: clipX,
                y: 0,
                width: chart.plotarea.width,
                height: chart.plotarea.height
            },
            args = {
                chartObj: chart
            };
        var clipID = effects.get(effects.svg_clips, 'rect', properties, args);
        holder.attr('clip-path', `url(${chart.defsLocation}#${clipID})`);
    }
}
